4	export type AssetInstanceStatus =
5	  | "IN_STOCK"
6	  | "AVAILABLE"
7	  | "ASSIGNED"
8	  | "IN_USE"
9	  | "RETURNING"
10	  | "REPAIRING"
11	  | "TRANSFERRING"
12	  | "LOST"
